------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
 CREATE TABLE active_mesocycle (id uuid, created_at timestamp with time zone, end_date date, start_date date, notes text, focus text, name text, status text);
 CREATE TABLE exercise_progression (date date, exercise text, reps_at_max_weight integer, max_weight_kg numeric, week_number integer, mesocycle_name text, exercise_id uuid);
 CREATE TABLE exercises (name text NOT NULL, notes text, movement_pattern text, equipment text, muscle_group text, created_at timestamp with time zone DEFAULT now(), id uuid NOT NULL DEFAULT gen_random_uuid());
 CREATE TABLE goals (mesocycle_id uuid, target_value numeric NOT NULL, target_reps integer, target_date date, achieved_at timestamp with time zone, created_at timestamp with time zone DEFAULT now(), notes text, goal_type text NOT NULL, id uuid NOT NULL DEFAULT gen_random_uuid(), exercise_id uuid);
 CREATE TABLE mesocycle_days (notes text, mesocycle_id uuid, day_number integer NOT NULL, created_at timestamp with time zone DEFAULT now(), id uuid NOT NULL DEFAULT gen_random_uuid(), name text NOT NULL);
 CREATE TABLE mesocycle_planned_exercises (id uuid NOT NULL DEFAULT gen_random_uuid(), mesocycle_day_id uuid, created_at timestamp with time zone DEFAULT now(), target_rpe numeric, notes text, target_sets integer, exercise_order integer NOT NULL, target_reps text, exercise_id uuid);
 CREATE TABLE mesocycles (created_at timestamp with time zone DEFAULT now(), progression_style text DEFAULT 'auto'::text, priority_muscles ARRAY, notes text, status text DEFAULT 'active'::text, focus text, name text NOT NULL, rpe_end integer DEFAULT 10, rpe_start integer DEFAULT 7, end_date date, start_date date NOT NULL, id uuid NOT NULL DEFAULT gen_random_uuid());
 CREATE TABLE run_hr_zones (created_at timestamp with time zone DEFAULT now(), max_hr integer, min_hr integer, duration_s numeric, zone_number integer NOT NULL, run_session_id uuid NOT NULL, id uuid NOT NULL DEFAULT gen_random_uuid());
 CREATE TABLE run_laps (created_at timestamp with time zone DEFAULT now(), avg_cadence integer, elevation_gain_m numeric, max_heart_rate integer, avg_heart_rate integer, avg_pace_s_per_km numeric, duration_s numeric, distance_m numeric, lap_number integer NOT NULL, run_session_id uuid NOT NULL, id uuid NOT NULL DEFAULT gen_random_uuid());
 CREATE TABLE run_sessions (avg_cadence integer, id uuid NOT NULL DEFAULT gen_random_uuid(), date date NOT NULL, started_at timestamp with time zone, ended_at timestamp with time zone, distance_m numeric, duration_s numeric, avg_pace_s_per_km numeric, avg_heart_rate integer, max_heart_rate integer, elevation_gain_m numeric, elevation_loss_m numeric, calories integer, training_effect_aerobic numeric, training_effect_anaerobic numeric, vo2_max_estimate numeric, perceived_effort integer, mesocycle_id uuid, created_at timestamp with time zone DEFAULT now(), run_type text, notes text, source text DEFAULT 'manual'::text, external_id text);
 CREATE TABLE superset_groups (id uuid NOT NULL DEFAULT gen_random_uuid(), name text, workout_id uuid, created_at timestamp with time zone DEFAULT now());
 CREATE TABLE weekly_targets (superset_group text, exercise_order integer NOT NULL, mesocycle_id uuid, notes text, week_number integer NOT NULL, target_sets integer NOT NULL, target_weight_kg numeric, created_at timestamp with time zone DEFAULT now(), id uuid NOT NULL DEFAULT gen_random_uuid(), target_reps text NOT NULL, exercise_id uuid, mesocycle_day_id uuid);
 CREATE TABLE weekly_volume_by_muscle (mesocycle_name text, mesocycle_id uuid, week_number integer, total_sets bigint, total_volume_kg numeric, muscle_group text);
 CREATE TABLE workout_exercise_notes (workout_id uuid, created_at timestamp with time zone DEFAULT now(), pump_quality integer, joint_discomfort integer, notes text NOT NULL, id uuid NOT NULL DEFAULT gen_random_uuid(), exercise_id uuid);
 CREATE TABLE workout_log (exercise text, workout_id uuid, date date, week_number integer, workout_rating integer, exercise_id uuid, set_order integer, weight_kg numeric, reps integer, rpe numeric, superset_group_id uuid, mesocycle_name text, mesocycle_focus text, day_name text, workout_notes text, mesocycle_id uuid, muscle_group text, equipment text, movement_pattern text, set_type text, set_notes text, exercise_notes text);
 CREATE TABLE workout_sets (reps integer, rpe numeric, created_at timestamp with time zone DEFAULT now(), superset_group_id uuid, exercise_id uuid, workout_id uuid, id uuid NOT NULL DEFAULT gen_random_uuid(), notes text, weight_kg numeric, set_type text, set_order integer NOT NULL);
 CREATE TABLE workout_volume_by_muscle (total_volume_kg numeric, workout_id uuid, total_sets bigint, muscle_group text, date date);
 CREATE TABLE workouts (sleep_quality integer, muscle_soreness jsonb, notes text, id uuid NOT NULL DEFAULT gen_random_uuid(), mesocycle_id uuid, mesocycle_day_id uuid, date date NOT NULL DEFAULT CURRENT_DATE, started_at timestamp with time zone, ended_at timestamp with time zone, pre_session_notes text, week_number integer, rating integer, created_at timestamp with time zone DEFAULT now(), energy_level integer);
